-- 016_unify_content_hash.sql
--
-- Wave 3 / D10. Mid-rollout the RSS worker switched
-- `content_hash` from sha256-of-something to
-- strictFingerprint(title, description) (sha1 over the sorted
-- character-4-gram shingle set of the Turkish-normalized
-- title+description). The cutover left ~6,638 sha1 articles
-- (40 hex chars) and ~10,668 sha256 articles (64 hex chars)
-- in the table that are duplicates of each other but invisible
-- to the `articles_source_content_hash_key` UNIQUE constraint.
--
-- This migration unifies every row to the canonical sha1 form,
-- repoints `cluster_articles` from loser rows to the survivors
-- (so cluster memberships are preserved), deletes losers, then
-- re-adds the UNIQUE constraint.
--
-- Hashes were precomputed in JS by `scripts/build-016-migration.mjs`
-- using the SAME `strictFingerprint(title, description)` the live
-- RSS worker uses, so the values written here are byte-for-byte
-- what `scripts/rss-worker.mjs` would emit on the next ingest.
--
-- The whole thing runs inside a single transaction. Re-running
-- after a successful apply is a near no-op: every row already
-- carries its canonical hash and the dedupe step finds nothing.

begin;

-- 0) Stage the precomputed (id, new_hash) pairs --------------------
create temp table tmp_article_new_hash (
  id uuid primary key,
  new_hash text not null
) on commit drop;




































-- 1) Diagnostics: report the before-state -------------------------
do $$
declare
  v_total_articles bigint;
  v_len_40 bigint;
  v_len_64 bigint;
  v_other_lengths bigint;
  v_will_change bigint;
begin
  select count(*) into v_total_articles from articles;
  select count(*) into v_len_40 from articles where length(content_hash) = 40;
  select count(*) into v_len_64 from articles where length(content_hash) = 64;
  select count(*) into v_other_lengths from articles where length(content_hash) not in (40, 64);
  select count(*) into v_will_change
    from articles a join tmp_article_new_hash t on t.id = a.id
    where a.content_hash is distinct from t.new_hash;
  raise notice 'BEFORE: total=%, sha1(40)=%, sha256(64)=%, other=%, hashes_changing=%',
    v_total_articles, v_len_40, v_len_64, v_other_lengths, v_will_change;
end $$;

-- 2) Drop the existing UNIQUE so we can rewrite hashes in place ----
--    (without this, mid-update collisions on rows that haven't been
--    deduped yet would abort the migration.)
alter table articles
  drop constraint if exists articles_source_content_hash_key;

-- 3) Pick survivors per (source_id, new_hash) group ----------------
--    Oldest created_at wins; tie-break on id for determinism.
create temp table tmp_dedupe_plan (
  loser_id uuid primary key,
  survivor_id uuid not null
) on commit drop;

with ranked as (
  select a.id,
         a.source_id,
         t.new_hash,
         a.created_at,
         row_number() over (
           partition by a.source_id, t.new_hash
           order by a.created_at asc nulls last, a.id asc
         ) as rn,
         first_value(a.id) over (
           partition by a.source_id, t.new_hash
           order by a.created_at asc nulls last, a.id asc
           rows between unbounded preceding and unbounded following
         ) as survivor_id
  from articles a
  join tmp_article_new_hash t on t.id = a.id
),
losers as (
  select id as loser_id, survivor_id from ranked where rn > 1
)
select loser_id, survivor_id from losers;

-- 4) Repoint cluster_articles from losers to survivors -------------
--    A survivor may already be a member of the same cluster — in
--    that case the loser's pointer is redundant and we just drop
--    it (handled by the on-conflict path: we delete the loser row
--    via FK cascade in step 5 anyway, so we only need to UPDATE
--    rows that DON'T collide).
do $$
declare
  v_repointed bigint;
  v_dropped bigint;
begin
  -- Drop redundant loser pointers where the survivor is already a member.
  with redundant as (
    select ca.cluster_id, ca.article_id
    from cluster_articles ca
    join tmp_dedupe_plan p on p.loser_id = ca.article_id
    where exists (
      select 1 from cluster_articles ca2
      where ca2.cluster_id = ca.cluster_id
        and ca2.article_id = p.survivor_id
    )
  )
  delete from cluster_articles ca
  using redundant r
  where ca.cluster_id = r.cluster_id
    and ca.article_id = r.article_id;
  get diagnostics v_dropped = row_count;

  -- Repoint the rest.
  update cluster_articles ca
  set article_id = p.survivor_id
  from tmp_dedupe_plan p
  where ca.article_id = p.loser_id;
  get diagnostics v_repointed = row_count;

  raise notice 'cluster_articles: redundant_dropped=%, repointed=%', v_dropped, v_repointed;
end $$;

-- 5) Delete loser articles -----------------------------------------
do $$
declare
  v_deleted bigint;
begin
  delete from articles a
  using tmp_dedupe_plan p
  where a.id = p.loser_id;
  get diagnostics v_deleted = row_count;
  raise notice 'articles loser rows deleted: %', v_deleted;
end $$;

-- 6) Rewrite content_hash on the survivors -------------------------
do $$
declare
  v_updated bigint;
begin
  update articles a
  set content_hash = t.new_hash
  from tmp_article_new_hash t
  where a.id = t.id
    and a.content_hash is distinct from t.new_hash;
  get diagnostics v_updated = row_count;
  raise notice 'articles content_hash updates: %', v_updated;
end $$;

-- 7) Re-add the UNIQUE constraint ----------------------------------
alter table articles
  add constraint articles_source_content_hash_key
  unique (source_id, content_hash);

-- 8) Recompute clusters.article_count + bias_distribution ---------
--    Mirrors migration 013 §2 — keeps the aggregates honest after
--    the cluster_articles repoint/drop cycle.
update clusters c set
  article_count = sub.cnt,
  bias_distribution = sub.dist,
  updated_at = now()
from (
  select bb.cluster_id,
         sum(bb.bias_count)::int as cnt,
         jsonb_object_agg(bb.bias, bb.bias_count) as dist
  from (
    select ca.cluster_id,
           s.bias,
           count(*)::int as bias_count
    from cluster_articles ca
    join articles a on a.id = ca.article_id
    join sources s on s.id = a.source_id
    group by ca.cluster_id, s.bias
  ) bb
  group by bb.cluster_id
) sub
where c.id = sub.cluster_id;

-- 9) Diagnostics: report the after-state ---------------------------
do $$
declare
  v_total_articles bigint;
  v_len_40 bigint;
  v_len_64 bigint;
  v_other_lengths bigint;
  v_dup_groups bigint;
begin
  select count(*) into v_total_articles from articles;
  select count(*) into v_len_40 from articles where length(content_hash) = 40;
  select count(*) into v_len_64 from articles where length(content_hash) = 64;
  select count(*) into v_other_lengths from articles where length(content_hash) not in (40, 64);
  select count(*) into v_dup_groups from (
    select 1 from articles
    group by source_id, content_hash
    having count(*) > 1
  ) z;
  raise notice 'AFTER: total=%, sha1(40)=%, sha256(64)=%, other=%, dup_source_hash_groups=%',
    v_total_articles, v_len_40, v_len_64, v_other_lengths, v_dup_groups;
end $$;

commit;
